import type {
  InternalMessage,
  ExtensionState,
} from "../types/index";

// URLs are loaded from config.json at runtime — no hardcoded values here.
import { APP_BASE, initConfig } from "../config";

// ─── Helpers ──────────────────────────────────────────────────────────────────
function send(msg: InternalMessage): Promise<any> {
  return new Promise((resolve, reject) => {
    chrome.runtime.sendMessage(msg, (response) => {
      if (chrome.runtime.lastError) reject(chrome.runtime.lastError);
      else resolve(response);
    });
  });
}

function $(id: string): HTMLElement {
  return document.getElementById(id)!;
}

// ─── UI Helpers ───────────────────────────────────────────────────────────────
function showLoading(text = "Loading…"): void {
  ($("view-loading") as HTMLElement).classList.remove("hidden");
  ($("view-home") as HTMLElement).classList.add("hidden");
  ($("view-room") as HTMLElement).classList.add("hidden");
  ($("loading-text") as HTMLElement).textContent = text;
}

function showHome(): void {
  ($("view-loading") as HTMLElement).classList.add("hidden");
  ($("view-home") as HTMLElement).classList.remove("hidden");
  ($("view-room") as HTMLElement).classList.add("hidden");
  clearError();
}

function showRoom(state: ExtensionState): void {
  ($("view-loading") as HTMLElement).classList.add("hidden");
  ($("view-home") as HTMLElement).classList.add("hidden");
  ($("view-room") as HTMLElement).classList.remove("hidden");
  if (state.roomState) {
    updateRoomUI(state);
  }
}

function showError(msg: string): void {
  const el = $("error-msg");
  el.textContent = msg;
  el.classList.remove("hidden");
  setTimeout(() => el.classList.add("hidden"), 5000);
}

function clearError(): void {
  $("error-msg").classList.add("hidden");
}

function updateRoomUI(state: ExtensionState): void {
  const room = state.roomState!;
  ($("room-id-display") as HTMLElement).textContent = room.roomId;
  ($("user-count") as HTMLElement).textContent = String(
    room.participants?.length ?? 1
  );

  const shareUrl = `${APP_BASE}/room/${room.roomId}`;
  ($("share-url-display") as HTMLElement).textContent = shareUrl;
  ($("movie-url-display") as HTMLElement).textContent = room.movieUrl ?? "—";

  // Show "Open Movie" button + hint only if the movie tab hasn't been opened yet
  const movieNotOpened = !state.activeTabId;
  $("btn-open-movie").classList.toggle("hidden", !movieNotOpened);
  $("copy-hint").classList.toggle("hidden", !movieNotOpened);

  // Sync mode pill
  const isSynced = room.syncMode === "SYNC";
  const pillSync = $("pill-sync");
  pillSync.classList.toggle("active", isSynced);
  pillSync.classList.toggle("sync", isSynced);
  ($("sync-mode-label") as HTMLElement).textContent = room.syncMode;

  // Control mode pill
  const isOwnerMode = room.controlMode === "OWNER";
  const pillControl = $("pill-control");
  const isOwner = state.userId === room.ownerId;
  pillControl.classList.toggle("active", isOwnerMode);
  pillControl.style.opacity = isOwner ? "1" : "0.5";
  pillControl.style.cursor = isOwner ? "pointer" : "not-allowed";
  ($("control-mode-label") as HTMLElement).textContent = room.controlMode;

  // WS badge
  const badge = $("ws-badge");
  badge.classList.toggle("connected", state.wsConnected);
  badge.classList.toggle("disconnected", !state.wsConnected);
}

// ─── Actions ──────────────────────────────────────────────────────────────────
async function createRoom(): Promise<void> {
  const url = ($("movie-url") as HTMLInputElement).value.trim();
  if (!url) {
    showError("Please enter a movie URL.");
    return;
  }
  try {
    new URL(url);
  } catch {
    showError("Please enter a valid URL.");
    return;
  }

  showLoading("Creating room…");
  try {
    const res = await send({ type: "CREATE_ROOM", payload: { movieUrl: url } });
    if (res.error) throw new Error(res.error);
    // State will be updated via message listener
  } catch (e: any) {
    showHome();
    showError(e.message ?? "Failed to create room.");
  }
}

async function joinRoom(): Promise<void> {
  const roomId = ($("join-room-id") as HTMLInputElement).value
    .trim()
    .toUpperCase();
  if (!roomId) {
    showError("Please enter a Room ID.");
    return;
  }

  showLoading("Joining room…");
  try {
    const res = await send({ type: "JOIN_ROOM", payload: { roomId } });
    if (res.error) throw new Error(res.error);
  } catch (e: any) {
    showHome();
    showError(e.message ?? "Failed to join room.");
  }
}

async function openMovie(): Promise<void> {
  const res = await send({ type: "OPEN_MOVIE" });
  if (res.error) { showError(res.error); return; }
  // Hide the button immediately — tab is now open
  $("btn-open-movie").classList.add("hidden");
  $("copy-hint").classList.add("hidden");
}

async function leaveRoom(): Promise<void> {
  showLoading("Leaving…");
  armLoadingWatchdog(); // recover if STATE_UPDATE never arrives
  await send({ type: "LEAVE_ROOM" });
  // Do NOT call showHome() here — background's resetLocalState() already
  // broadcasts STATE_UPDATE which the listener below handles. Calling
  // showHome() here too causes a double-render race on slow connections.
}

async function toggleSyncMode(): Promise<void> {
  try {
    await send({ type: "TOGGLE_SYNC_MODE" });
  } catch (e: any) {
    showError(e.message ?? "Failed to toggle sync mode.");
  }
}

async function toggleControlMode(): Promise<void> {
  try {
    const res = await send({ type: "TOGGLE_CONTROL_MODE" });
    if (res.error) showError(res.error);
  } catch (e: any) {
    showError(e.message ?? "Failed to toggle control mode.");
  }
}

function copyShareUrl(): void {
  const el = $("share-url-display");
  const url = el.textContent ?? "";
  if (!url || url === "—") return;
  navigator.clipboard.writeText(url).then(() => {
    const btn = $("copy-btn") as HTMLButtonElement;
    btn.textContent = "✓ Copied";
    btn.classList.add("copied");
    setTimeout(() => {
      btn.textContent = "Copy";
      btn.classList.remove("copied");
    }, 2000);
  });
}

// ─── Message Listener (from background) ──────────────────────────────────────
chrome.runtime.onMessage.addListener((message: InternalMessage) => {
  switch (message.type) {
    case "STATE_UPDATE":
      const extState = message.payload as ExtensionState;
      if (extState.roomState) {
        showRoom(extState);
      } else {
        showHome();
      }
      break;
    case "WS_CONNECTED":
    case "WS_DISCONNECTED":
      // Re-fetch state to update badge
      refreshState();
      break;
  }
});

// ─── Init ─────────────────────────────────────────────────────────────────────
async function refreshState(): Promise<void> {
  try {
    const res = await send({ type: "GET_STATE" });
    const extState: ExtensionState = res.state;
    if (extState.userId) currentUserId = extState.userId;
    if (extState.roomState) {
      showRoom(extState);
    } else {
      showHome();
    }
    const badge = $("ws-badge");
    badge.classList.toggle("connected", extState.wsConnected);
    badge.classList.toggle("disconnected", !extState.wsConnected);
  } catch {
    // Background service worker not reachable or returned nothing
    showHome();
  }
}

// Safety net: if the popup is stuck on the loading screen (e.g. leaveRoom
// fired but STATE_UPDATE from background never arrived), auto-recover after
// 4 seconds by re-fetching state directly.
let loadingWatchdog: ReturnType<typeof setTimeout> | null = null;
function armLoadingWatchdog(): void {
  if (loadingWatchdog) clearTimeout(loadingWatchdog);
  loadingWatchdog = setTimeout(() => {
    const loadingEl = $("view-loading");
    if (!loadingEl.classList.contains("hidden")) {
      console.warn("[WatchTogether Popup] Stuck on loading — recovering via GET_STATE");
      refreshState();
    }
  }, 4000);
}

// ─── Chat ─────────────────────────────────────────────────────────────────────
import type { ChatMessage } from "../types/index";

let currentUserId = "";

function appendChatMessage(msg: ChatMessage): void {
  const msgs = $("chat-messages");
  if (!msgs) return;
  const isMine = msg.userId === currentUserId;
  const row = document.createElement("div");
  row.style.cssText = `display:flex;flex-direction:column;gap:2px;align-items:${isMine ? "flex-end" : "flex-start"};`;
  if (!isMine) {
    const name = document.createElement("div");
    name.className = "chat-msg-name";
    name.textContent = msg.displayName;
    row.appendChild(name);
  }
  const body = document.createElement("div");
  body.className = `chat-msg-body${isMine ? " chat-msg-mine" : ""}`;
  if (msg.isGif) {
    const img = document.createElement("img");
    img.src = msg.text;
    img.style.cssText = "max-width:180px;max-height:120px;border-radius:8px;display:block;";
    body.appendChild(img);
  } else {
    body.textContent = msg.text;
  }
  row.appendChild(body);
  msgs.appendChild(row);
  msgs.scrollTop = msgs.scrollHeight;
  // Red dot badge when not on chat tab
  const chatBtn = $("tab-chat-btn");
  if (chatBtn && !chatBtn.classList.contains("active") && !isMine) {
    chatBtn.textContent = "💬 Chat 🔴";
  }
}

async function sendChat(): Promise<void> {
  const input = $("chat-input") as HTMLInputElement;
  const text = input.value.trim();
  if (!text) return;
  input.value = "";
  await send({ type: "SEND_CHAT", payload: { text, isGif: false } });
}

async function searchGif(): Promise<void> {
  const q = ($("gif-search-input") as HTMLInputElement).value.trim();
  if (!q) return;
  const results = $("gif-results");
  results.style.display = "flex";
  results.innerHTML = "<span style='color:var(--muted);font-size:11px;padding:4px;'>Searching…</span>";
  try {
    let gifs: {url: string}[] = [];

    // Try Tenor first
    try {
      const r = await fetch(`https://tenor.googleapis.com/v2/search?q=${encodeURIComponent(q)}&key=AIzaSyB_63SFMSXX5k-wLKQtmVMPZe6nhqw&limit=8&media_filter=gif`);
      const data = await r.json();
      gifs = (data.results || []).map((res: any) => ({
        url: res.media_formats?.gif?.url || res.media_formats?.tinygif?.url
      })).filter((g: any) => g.url);
    } catch {}

    // Fallback to Giphy if Tenor returns nothing
    if (!gifs.length) {
      const g = await fetch(`https://api.giphy.com/v1/gifs/search?api_key=0UTRbFtkMxAplrohufYco1HcGWrNyO&q=${encodeURIComponent(q)}&limit=8&rating=g`);
      const gd = await g.json();
      gifs = (gd.data || []).map((res: any) => ({
        url: res.images?.fixed_height_small?.url || res.images?.original?.url
      })).filter((g: any) => g.url);
    }

    results.innerHTML = "";
    gifs.forEach(({ url }) => {
      const img = document.createElement("img");
      img.src = url;
      img.style.cssText = "width:72px;height:54px;object-fit:cover;border-radius:6px;cursor:pointer;";
      img.addEventListener("click", async () => {
        await send({ type: "SEND_CHAT", payload: { text: url, isGif: true } });
        results.style.display = "none";
        ($("gif-search-input") as HTMLInputElement).value = "";
      });
      results.appendChild(img);
    });
    if (!results.children.length) results.innerHTML = "<span style='color:var(--muted);font-size:11px;'>No results</span>";
  } catch {
    results.innerHTML = "<span style='color:var(--danger);font-size:11px;'>Search failed</span>";
  }
}

function switchTab(tab: "room" | "chat"): void {
  const roomActions = $("room-actions");
  const viewChat = $("view-chat");
  const roomBtn = $("tab-room-btn");
  const chatBtn = $("tab-chat-btn");
  const roomCard = document.querySelector(".room-card") as HTMLElement | null;
  const copyHint = document.getElementById("copy-hint");
  const openMovieBtn = document.getElementById("btn-open-movie");
  if (tab === "room") {
    roomActions.classList.remove("hidden");
    viewChat.classList.add("hidden");
    viewChat.style.display = "none";
    roomBtn.classList.add("active");
    chatBtn.classList.remove("active");
    chatBtn.textContent = "💬 Chat";
    if (roomCard) roomCard.style.display = "";
    if (copyHint) copyHint.classList.remove("hidden");
    if (openMovieBtn) openMovieBtn.classList.remove("hidden");
    // re-apply state to restore correct visibility
    send({ type: "GET_STATE" }).then((res) => { if (res?.state?.roomState) updateRoomUI(res.state); });
  } else {
    roomActions.classList.add("hidden");
    viewChat.classList.remove("hidden"); // must remove hidden class first
    viewChat.style.display = "flex";
    chatBtn.classList.add("active");
    chatBtn.textContent = "💬 Chat";
    roomBtn.classList.remove("active");
    if (roomCard) roomCard.style.display = "none";
    if (copyHint) copyHint.classList.add("hidden");
    if (openMovieBtn) openMovieBtn.classList.add("hidden");
    const msgs = $("chat-messages");
    if (msgs) msgs.scrollTop = msgs.scrollHeight;
  }
}

// Incoming chat from background (other user's message)
chrome.runtime.onMessage.addListener((message: import("../types/index").InternalMessage) => {
  if (message.type === "CHAT_RECEIVED") {
    appendChatMessage(message.payload as ChatMessage);
  }
});

// ─── Update Room URL ──────────────────────────────────────────────────────────
function initUpdateUrl(): void {
  const btn = document.getElementById("btn-update-url");
  const row = document.getElementById("update-url-row");
  const confirmBtn = document.getElementById("btn-confirm-url");
  const input = document.getElementById("new-url-input") as HTMLInputElement;
  if (!btn || !row || !confirmBtn || !input) return;

  btn.addEventListener("click", () => {
    row.classList.toggle("hidden");
    if (!row.classList.contains("hidden")) input.focus();
  });

  const doUpdate = async () => {
    const url = input.value.trim();
    if (!url) return;
    try { new URL(url); } catch { showError("Invalid URL"); return; }
    const res = await send({ type: "UPDATE_ROOM_URL", payload: { movieUrl: url } });
    if (res.error) { showError(res.error); return; }
    input.value = "";
    row.classList.add("hidden");
  };

  confirmBtn.addEventListener("click", doUpdate);
  input.addEventListener("keydown", (e) => { if ((e as KeyboardEvent).key === "Enter") doUpdate(); });
}

// ─── Voice Chat ───────────────────────────────────────────────────────────────
// SpeechRecognition is NOT available in extension popups (sandboxed context).
// We delegate to the content script (real page context) via background.

let voiceMode = false;

function initVoiceChat(): void {
  // Listen for transcripts coming back from content script via background
  chrome.runtime.onMessage.addListener((message: import("../types/index").InternalMessage) => {
    if (message.type !== "VOICE_TRANSCRIPT") return;
    const { text, isFinal } = message.payload || {};
    const chatInput = document.getElementById("chat-input") as HTMLInputElement;
    if (!chatInput) return;
    // Show interim text in input as visual feedback
    chatInput.value = text || "";
    // Clear input when final is sent (background handles the actual send)
    if (isFinal) {
      setTimeout(() => { chatInput.value = ""; }, 300);
    }
  });
}

async function startVoice(): Promise<void> {
  voiceMode = true;
  await send({ type: "START_VOICE" });
  const btn = document.getElementById("btn-voice-toggle")!;
  const input = document.getElementById("chat-input") as HTMLInputElement;
  btn.textContent = "🔴";
  btn.style.background = "rgba(255,71,87,0.2)";
  btn.style.borderColor = "rgba(255,71,87,0.5)";
  btn.style.color = "#ff4757";
  btn.title = "Voice active — click to stop";
  input.placeholder = "Listening…";
  input.readOnly = true;
}

async function stopVoice(): Promise<void> {
  voiceMode = false;
  await send({ type: "STOP_VOICE" });
  const btn = document.getElementById("btn-voice-toggle")!;
  const input = document.getElementById("chat-input") as HTMLInputElement;
  btn.textContent = "🎤";
  btn.style.background = "rgba(255,255,255,0.07)";
  btn.style.borderColor = "var(--border)";
  btn.style.color = "var(--muted)";
  btn.title = "Switch to voice input";
  input.placeholder = "Message or emoji…";
  input.readOnly = false;
  input.value = "";
  input.focus();
}

function toggleVoice(): void {
  voiceMode ? stopVoice() : startVoice();
}

document.addEventListener("DOMContentLoaded", async () => {
  await initConfig();

  $("btn-create").addEventListener("click", createRoom);
  $("btn-join").addEventListener("click", joinRoom);
  $("btn-leave").addEventListener("click", leaveRoom);
  $("btn-leave-chat").addEventListener("click", leaveRoom);
  $("btn-open-movie").addEventListener("click", openMovie);
  $("btn-copy-link").addEventListener("click", copyShareUrl);
  $("copy-btn").addEventListener("click", copyShareUrl);
  $("pill-sync").addEventListener("click", toggleSyncMode);
  $("pill-control").addEventListener("click", toggleControlMode);
  $("tab-room-btn").addEventListener("click", () => switchTab("room"));
  $("tab-chat-btn").addEventListener("click", () => switchTab("chat"));
  $("chat-send-btn").addEventListener("click", sendChat);
  $("gif-search-btn").addEventListener("click", searchGif);
  $("btn-voice-toggle").addEventListener("click", toggleVoice);
  $("chat-input").addEventListener("keydown", (e) => { if ((e as KeyboardEvent).key === "Enter") sendChat(); });
  $("gif-search-input").addEventListener("keydown", (e) => { if ((e as KeyboardEvent).key === "Enter") searchGif(); });
  $("join-room-id").addEventListener("input", (e) => {
    (e.target as HTMLInputElement).value = (e.target as HTMLInputElement).value.toUpperCase();
  });

  // Emoji picker
  const EMOJIS = ["😂","❤️","😍","🤣","😊","🙏","💕","😭","😘","👍","😁","🔥","💔","💖","😢","🤔","😎","😩","🥺","😏","💪","🙄","😜","🎉","🥳","😤","🙃","😅","😆","🤩","👏","😋","✨","🤯","😳","🤗","💯","🎶","👀","😴","😈","👻","🤦","🤷","💀","🥰","😻","🫶","🫠","🫡","💬","🗣️","🎬","🍿","🎥","📺","🎮"];
  const picker = $("emoji-picker");
  EMOJIS.forEach(em => {
    const btn = document.createElement("button");
    btn.textContent = em;
    btn.style.cssText = "background:none;border:none;cursor:pointer;font-size:18px;padding:2px;border-radius:4px;";
    btn.addEventListener("click", () => {
      ($("chat-input") as HTMLInputElement).value += em;
      ($("chat-input") as HTMLInputElement).focus();
    });
    picker.appendChild(btn);
  });
  $("btn-emoji-toggle").addEventListener("click", () => {
    const isHidden = picker.classList.contains("hidden");
    if (isHidden) {
      picker.classList.remove("hidden");
      picker.style.display = "flex";
    } else {
      picker.classList.add("hidden");
      picker.style.display = "none";
    }
  });

  initUpdateUrl();
  initVoiceChat();

  const state = await send({ type: "GET_STATE" }).catch(() => null);
  if (state?.state?.userId) currentUserId = state.state.userId;
  refreshState();
});
